1	const cellKey = (cell: number[]): string => `${cell[0]},${cell[1]}`;
2	
3	const isNeighbor = (cell: number[], other: number[]): boolean =>
4	  !(other[0] === cell[0] && other[1] === cell[1]) &&
5	  Math.abs(other[0] - cell[0]) <= 1 &&
6	  Math.abs(other[1] - cell[1]) <= 1;
7	
8	const countNeighbors = (cell: number[], liveCells: number[][]): number =>
9	  liveCells.filter((other) => isNeighbor(cell, other)).length;
10	
11	const getDeadNeighbors = (liveCells: number[][]): number[][] => {
12	  const liveSet = new Set(liveCells.map(cellKey));
13	  const seen = new Set<string>();
14	  const result: number[][] = [];
15	
16	  for (const cell of liveCells) {
17	    for (let dx = -1; dx <= 1; dx++) {
18	      for (let dy = -1; dy <= 1; dy++) {
19	        if (dx === 0 && dy === 0) continue;
20	        const candidate = [cell[0] + dx, cell[1] + dy];
21	        const key = cellKey(candidate);
22	        if (!liveSet.has(key) && !seen.has(key)) {
23	          seen.add(key);
24	          result.push(candidate);
25	        }
26	      }
27	    }
28	  }
29	
30	  return result;
31	};
32	
33	export function nextGeneration(liveCells: number[][]): number[][] {
34	  const survivors = liveCells.filter((cell) => {
35	    const neighborCount = countNeighbors(cell, liveCells);
36	    return neighborCount === 2 || neighborCount === 3;
37	  });
38	
39	  const births = getDeadNeighbors(liveCells).filter(
40	    (cell) => countNeighbors(cell, liveCells) === 3
41	  );
42	
43	  return [...survivors, ...births];
44	}
